#!/usr/bin/env bash
# Link local packages using npm link
set -e
ROOT=$(pwd)

cd envapt
echo "Linking envapt globally..."
npm link
cd "$ROOT/envapt-superimg"
echo "Linking envapt into envapt-superimg"
npm link envapt
cd "$ROOT/envapt-nezlephant"
echo "Linking envapt into envapt-nezlephant"
npm link envapt
cd "$ROOT/nezlephant"
echo "Linking nezlephant globally..."
npm link
cd "$ROOT/envapt-nezlephant"
echo "Linking nezlephant into envapt-nezlephant"
npm link @funeste38/nezlephant

echo "Linking complete."